```javascript
hs.ui.dialog("Save changes?")
    .informativeText("Your document has unsaved changes.")
    .buttons(["Save", "Don't Save", "Cancel"])
    .onButton((index) => {
        if (index === 0) {
            console.log("Saving...");
        } else if (index === 1) {
            console.log("Discarding changes...");
        }
    })
    .show();
```

